// mm/src/components/ui/OrderSummary.js
import React, { useMemo } from 'react';

const DEFAULT_PACKAGE_PRICES = {
  basic: 49,
  standard: 99,
  premium: 199,
};

function formatAuthor(details) {
  const parts = [
    (details?.prefix || '').trim(),
    (details?.firstName || '').trim(),
    (details?.middleName || '').trim(),
    (details?.lastName || '').trim(),
    (details?.suffix || '').trim(),
  ].filter(Boolean);

  return parts.length ? parts.join(' ') : '';
}

export default function OrderSummary({
  bookTitle,
  details,
  design,
  packageId,
  packagePrices = DEFAULT_PACKAGE_PRICES,
  className = '',
}) {
  const authorName = useMemo(() => formatAuthor(details), [details]);
  const total = packagePrices?.[packageId] ?? 0;

  const formatLine = useMemo(() => {
    const t = design?.typography ? `Typography: ${design.typography}` : null;
    const l = design?.layout ? `Layout: ${design.layout}` : null;
    const s = design?.trim ? `Trim: ${design.trim}` : null;
    return [t, l, s].filter(Boolean).join(' • ');
  }, [design]);

  return (
    <div className={['border rounded-xl p-6 bg-white', className].join(' ')}>
      <h3 className="text-2xl font-semibold text-slate-900">Order Summary</h3>

      <div className="mt-6 space-y-3 text-sm">
        <div className="flex items-center justify-between">
          <span className="text-slate-600">Book Title:</span>
          <span className="text-slate-900 font-medium">{bookTitle || '—'}</span>
        </div>

        <div className="flex items-center justify-between">
          <span className="text-slate-600">Author:</span>
          <span className="text-slate-900 font-medium">{authorName || '—'}</span>
        </div>

        <div className="flex items-center justify-between">
          <span className="text-slate-600">Format:</span>
          <span className="text-slate-900 font-medium text-right">{formatLine || '—'}</span>
        </div>
      </div>

      <div className="mt-6 border-t pt-4 flex items-center justify-between">
        <span className="text-slate-900 font-semibold text-lg">Total:</span>
        <span className="text-slate-900 font-semibold text-lg">${total}</span>
      </div>
    </div>
  );
}
